     3|import { useEffect, useState } from "react";
     4|import Link from "next/link";
     5|import { usePathname } from "next/navigation";
     6|import { cn } from "@/lib/utils";
     7|import { ALL_LOCALES, type Locale } from "@/lib/i18n/config";
     8|import type { NavStrings } from "@/lib/i18n/dictionary";
     9|
    10|interface NavbarProps {
    11|  t: NavStrings;
    12|  locale: Locale;
    13|}
    14|
    15|export function Navbar({ t, locale }: NavbarProps) {
    16|  const [scrolled, setScrolled] = useState(false);
    17|  const [mobileOpen, setMobileOpen] = useState(false);
    18|  const [langOpen, setLangOpen] = useState(false);
    19|  const pathname = usePathname();
    20|
    21|  useEffect(() => {
    22|    const onScroll = () => setScrolled(window.scrollY > 50);
    23|    window.addEventListener("scroll", onScroll, { passive: true });
    24|    return () => window.removeEventListener("scroll", onScroll);
    25|  }, []);
    26|
    27|  const links = [
    28|    { href: "#experience", label: t.experience },
    29|    { href: "#skills", label: t.skills },
    30|    { href: "#portfolio", label: t.portfolio },
    31|    { href: "#recommendations", label: t.recommendations },
    32|    { href: "#contact", label: t.contact },
    33|  ];
    34|
    35|  const switchLocale = (l: Locale) => {
    36|    if (l === locale) return;
    37|    const segments = pathname.split("/").filter(Boolean);
    38|    if (ALL_LOCALES.includes(segments[0] as Locale)) {
    39|      segments[0] = l;
    40|    } else {
    41|      segments.unshift(l);
    42|    }
    43|    window.location.href = "/" + segments.join("/");
    44|  };
    45|
    46|  return (
    47|    <>
    48|      <nav
    49|        className={cn(
    50|          "fixed top-0 z-50 w-full transition-all duration-300",
    51|          scrolled
    52|            ? "border-b border-border bg-background/95 backdrop-blur-xl shadow-nav"
    53|            : "bg-background/70 backdrop-blur-sm"
    54|        )}
    55|      >
    56|        <div className="mx-auto flex h-16 max-w-6xl items-center justify-between px-4 sm:px-6 lg:px-8">
    57|          <Link
    58|            href={locale === "en" ? "/" : `/${locale}`}
    59|            className="text-lg font-display font-bold text-foreground hover:text-primary transition-colors"
    60|          >
    61|            ND
    62|          </Link>
    63|
    64|          <div className="hidden items-center gap-1 md:flex">
    65|            {links.map((link) => (
    66|              <a
    67|                key={link.href}
    68|                href={link.href}
    69|                className="rounded-lg px-3 py-2 text-sm font-medium text-muted-foreground transition-colors hover:text-foreground hover:bg-surface-alt"
    70|              >
    71|                {link.label}
    72|              </a>
    73|            ))}
    74|          </div>
    75|
    76|          <div className="flex items-center gap-2">
    77|            <div className="relative">
    78|              <button
    79|                onClick={() => setLangOpen(!langOpen)}
    80|                className="rounded-lg px-2.5 py-2 text-sm font-medium text-muted-foreground hover:text-foreground hover:bg-surface-alt transition-colors"
    81|                aria-label="Switch language"
    82|              >
    83|                {locale.toUpperCase()}
    84|              </button>
    85|              {langOpen && (
    86|                <>
    87|                  <div className="fixed inset-0 z-40" onClick={() => setLangOpen(false)} />
    88|                  <div className="absolute right-0 top-full mt-1 z-50 w-28 rounded-xl border border-border bg-surface shadow-lg py-1">
    89|                    {ALL_LOCALES.map((l) => (
    90|                      <button
    91|                        key={l}
    92|                        onClick={() => {
    93|                          switchLocale(l);
    94|                          setLangOpen(false);
    95|                        }}
    96|                        className={cn(
    97|                          "w-full px-4 py-2 text-left text-sm transition-colors",
    98|                          l === locale
    99|                            ? "text-primary font-medium bg-primary/5"
   100|                            : "text-muted-foreground hover:text-foreground hover:bg-surface-alt"
   101|                        )}
   102|                      >
   103|                        {l === "en" ? "English" : "Español"}
   104|                      </button>
   105|                    ))}
   106|                  </div>
